239	
240	      {# Determine which preset is active #}
241	      {% if current_days is none %}
242	        {% set active_preset = "" %}
243	      {% elif current_days | string in preset_values %}
244	        {% set active_preset = current_days | string %}
245	      {% else %}
246	        {% set active_preset = "custom" %}
247	      {% endif %}
